<span class="line">    <span class="token parameter variable">--env</span> <span class="token assign-left variable">MINIO_ROOT_PASSWORD</span><span class="token operator">=</span><span class="token string">&quot;123456789&quot;</span> <span class="token punctuation">\\</span></span>
